-- =============================================
-- B-02: 4 players, 1 mafioso — مكتب عقارات في الشيخ زايد
-- =============================================
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language)
VALUES (
  'B-02',
  'ابتزاز',
  'عقود الشيخ زايد',
  'في مكتب عقارات كبير في الشيخ زايد، صاحب المكتب أبو خالد بدأ يوصله رسايل على واتساب من نمرة مش معروفة فيها صور لعقود مزوّرة بتوقيعه، واللي باعتها بيطلب منه تلتمية ألف جنيه كل شهر ولا العقود هتوصل للنيابة. أبو خالد عارف إن العقود دي مكانتش غير في الخزنة بتاعته في المكتب ومفيش غير ناس معدودة ليهم وصول.',
  4,
  1,
  'سلوى',
  'العقود المزوّرة اتصوّرت وهي على المكتب مش في الخزنة، يعني حد صورها وقت ما أبو خالد كان بيراجعها؛ الصور فيها ظل إيد حد ماسك موبايل وباين إن الصورة اتاخدت بسرعة؛ الرسايل بدأت بعد ما أبو خالد أعلن إنه هيقلّل العمولات بتاعة الموظفين من الشهر الجاي.',
  'سلوى المحاسبة كانت الوحيدة اللي قاعدة في المكتب يوم الخميس اللي العقود اتصوّرت فيه؛ فيه سجل دخول بيبيّن إن حد فتح الخزنة الساعة ٣ العصر واللي عنده الكود هم تلت أشخاص بس؛ نبيل كان عنده موعد مع عميل في نفس الوقت بس العميل ده محدش شافه.',
  'نمرة الواتساب اللي بتبعت التهديدات متسجلة بشريحة اتشترت من محل في الشيخ زايد على بعد شارعين من المكتب؛ كاميرا المحل بتبيّن ست لابسة نضارة شمس اشترت الشريحة؛ سلوى عندها نفس النضارة في صفحتها على فيسبوك؛ الفلوس اللي اتطلبت هي نفس مبلغ الفرق اللي سلوى كانت بتقول إن أبو خالد ناقصها من حساباتها.',
  'سلوى هي اللي صوّرت العقود لما أبو خالد سابها على المكتب وراح يصلي الضهر، واشترت شريحة جديدة عشان تبعتله التهديدات. السبب إن أبو خالد كان بياخد نسبة من عمولتها من غير ما يقولها وكمان قلّل مرتبها مرتين، فقررت تبتزه عشان تاخد فلوسها وتعويض.',
  'نبيل — كان بيعمل شغل سمسرة لوحده من ورا أبو خالد وبياخد عمولة من العملاء على جنب؛ هاني — لقى نسخة من العقود المزوّرة في الطابعة بالغلط ومسحها بس مقالش لحد عشان خايف يتورط؛ جمال — كان بيستخدم كمبيوتر المكتب بالليل يشتغل شغل فريلانس وعنده باسورد الخزنة القديم.',
  'production_ready',
  'ar-EG'
);

INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-02'), 'سلوى', 1, 'المحاسبة اللي شغالة في المكتب من أربع سنين وبتتعامل مع كل الفلوس والعقود وعندها كود الخزنة', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-02'), 'نبيل', 2, 'مسؤول المبيعات اللي بيجيب عملاء كتير وبيطلع معاهم يعاين شقق وعنده مفتاح المكتب', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-02'), 'هاني', 3, 'الموظف الجديد اللي بيتعلم الشغل ومسؤول عن الأرشيف والطباعة وبيقعد لوحده كتير في أوضة الملفات', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-02'), 'جمال', 4, 'حارس المكتب اللي بيقعد بالليل وعنده مفاتيح كل حاجة وبيعرف مين بيدخل ومين بيطلع', false);

-- =============================================
-- B-05: 4 players, 1 mafioso — استوديو يوتيوب في الدقي
-- =============================================
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language)
VALUES (
  'B-05',
  'ابتزاز',
  'فضيحة اليوتيوبر',
  'في استوديو يوتيوب في الدقي، اليوتيوبر المشهور عصام لقى إيميل فيه مقاطع فيديو ليه وهو بيتكلم كلام وحش على المتابعين بتوعه وبيقول إنهم أغبياء وبيصرف عليهم فلوس عشان يزوّد المشاهدات. الإيميل فيه تهديد: "ادفع ربع مليون ولا الفيديوهات دي هتنزل وهتخسر كل جمهورك." عصام مش فاهم مين سجّله عشان الكلام ده كان في الاستوديو وهو بيفتكر إنه لوحده.',
  4,
  1,
  'آدم',
  'الفيديوهات اتسجلت من كاميرا الاستوديو نفسها مش من موبايل؛ التسجيلات من أيام مختلفة يعني مش صدفة ده حد مترصّد عصام؛ الكاميرا اللي في الاستوديو المفروض مبتسجلش غير وقت التصوير الرسمي بس حد غيّر الإعدادات؛ فيه أربع أشخاص بس عندهم وصول لكاميرات الاستوديو.',
  'آدم مسؤول المونتاج كان بيقعد لوحده في الاستوديو بالليل "يخلّص حلقات"؛ فيه حد غيّر إعدادات الكاميرا الرئيسية خلّاها تسجل ٢٤ ساعة بدل ما تسجل وقت التصوير بس؛ إيمان كانت بتشتكي إن عصام بينسب شغلها لنفسه؛ التسجيلات المسروقة كلها من آخر شهر بس.',
  'لوج الكاميرا بيبيّن إن حد دخل على الإعدادات من كمبيوتر المونتاج بتاع آدم؛ الإيميل اللي فيه التهديد اتبعت من VPN بس الـ VPN ده مربوط باشتراك مدفوع بفيزا آدم الشخصية؛ آدم كان قدّم على شغل في قناة تانية وعايز يمشي بس عصام رافض يفسخ العقد ومديله شرط جزائي كبير؛ مبلغ الابتزاز قريب جداً من الشرط الجزائي اللي في عقد آدم.',
  'آدم هو اللي غيّر إعدادات الكاميرا عشان تسجل عصام وهو بيتكلم على راحته في الاستوديو. جمع التسجيلات على مدار شهر وبعتها من إيميل مزيف عشان عصام يدفعله فلوس تغطي الشرط الجزائي بتاع العقد ويقدر يمشي ويشتغل في القناة التانية.',
  'إيمان — كانت بتنزّل حلقات على قناتها الشخصية من غير ما عصام يعرف وبتستخدم أدوات الاستوديو؛ كريم — كان بيصور بالموبايل كواليس من غير إذن وبيبيعها لصفحات جوسيب؛ مريم — كانت بتاخد سكريبتات الحلقات وتبيعها ليوتيوبرز تانيين عشان محتاجة فلوس.',
  'production_ready',
  'ar-EG'
);

INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-05'), 'آدم', 1, 'مسؤول المونتاج اللي بيشتغل مع عصام من سنتين وعنده وصول لكل الكاميرات والملفات وبيقعد في الاستوديو لوحده كتير', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-05'), 'إيمان', 2, 'مديرة المحتوى اللي بتكتب السكريبتات وبتنظم جدول التصوير وزعلانة إن عصام مش بيقدّر شغلها', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-05'), 'كريم', 3, 'المصور اللي بيصور الحلقات وبيحب يصور كواليس وبيعرف كل زوايا الاستوديو', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-05'), 'مريم', 4, 'مسؤولة السوشيال ميديا اللي بتنزّل المحتوى وبتتعامل مع كل حسابات عصام وعندها كل الباسوردات', false);

-- =============================================
-- B-08: 4 players, 1 mafioso — مصنع حلويات في حلوان
-- =============================================
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language)
VALUES (
  'B-08',
  'ابتزاز',
  'سر المصنع',
  'في مصنع حلويات مشهور في حلوان، صاحب المصنع أبو ياسر بدأ يلاقي جوابات على باب بيته فيها صور لتقارير صحية مزوّرة بتثبت إن المصنع بيستخدم مواد منتهية الصلاحية. كل جواب فيه تهديد: "ادفع ميتين ألف ولا التقارير دي هتوصل لوزارة الصحة والجرايد." أبو ياسر عارف إن التقارير دي كانت في مكتبه المقفول في المصنع ومحدش المفروض يوصلها.',
  4,
  1,
  'منى',
  'التقارير الصحية المزوّرة كانت في ملف في درج المكتب مش في الخزنة يعني أسهل في الوصول؛ الصور اتاخدت بكاميرا موبايل والفلاش باين فيها؛ التهديدات بدأت بعد ما أبو ياسر فصل عاملين من المصنع الشهر اللي فات؛ اللي بيبعت الجوابات عارف عنوان بيت أبو ياسر الشخصي.',
  'منى مسؤولة الجودة كانت الوحيدة اللي بتدخل مكتب أبو ياسر وقت ما بيكون في جولة التفتيش في خط الإنتاج؛ فيه بصمات على الملف بتاعة أكتر من شخص؛ عادل كان زعلان عشان أبو ياسر رفض يديله علاوة؛ جواب التهديد الأول كان مكتوب بخط إيد ومش مطبوع.',
  'خبير خطوط كتب إن الخط اللي في الجواب الأول قريب من خط منى اللي في تقارير الجودة بتاعتها؛ منى كانت عارفة عنوان بيت أبو ياسر عشان هي اللي بتوصّله ورق المصنع على البيت ساعات؛ الشريحة اللي بتيجي منها مكالمات تهديد اتشترت من حلوان بفلوس كاش؛ منى كانت هتتنقل لفرع تاني بمرتب أقل والموضوع ده كان مضايقها جداً.',
  'منى هي اللي صوّرت التقارير الصحية من مكتب أبو ياسر وقت ما كان بيعمل جولة تفتيش في المصنع. كتبت الجواب الأول بإيدها ولما حست إن ممكن يتعرف على خطها بدأت تطبع الباقي. السبب إن أبو ياسر كان بينقلها لفرع تاني بمرتب أقل عشان جاب واحدة مكانها بنت واحد صاحبه، فقررت تبتزه عشان يسيبها مكانها ويديها فلوس كمان.',
  'عادل — كان بياخد حلويات من المصنع كل يوم ويبيعها على جنب وخايف لو حد عرف هيتفصل؛ سامي — كان عارف إن التقارير الصحية فيها مشاكل وبيفكر يبلّغ بس خايف يخسر شغله؛ رضا — كان بيسيب باب المصنع مفتوح بالليل عشان صاحبه ييجي ياخد بواقي إنتاج ببلاش.',
  'production_ready',
  'ar-EG'
);

INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-08'), 'منى', 1, 'مسؤولة الجودة اللي بتفتّش على خطوط الإنتاج وبتدخل مكتب أبو ياسر كل يوم وعندها وصول لكل الملفات الصحية', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-08'), 'عادل', 2, 'مشرف خط الإنتاج اللي شغال في المصنع من عشر سنين وزعلان عشان مبياخدش علاوات', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-08'), 'سامي', 3, 'المهندس الكيميائي اللي بيحلل المواد الخام وعارف كل تفاصيل التقارير الصحية', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-08'), 'رضا', 4, 'حارس المصنع الليلي اللي عنده مفاتيح كل الأبواب وبيعرف مين بيدخل بالليل', false);
